sql.if:
and sp.id = #{id}
            
                and sp.starttime   >   #{stime}
                and ADDTIME(sp.endtime,'23:59:59')   <  #{stime}
                and ADDTIME(sp.endtime,'23:59:59')   >   #{stime} and sp.starttime
                      <  #{stime}

mapper.select:
select sp.* ,DATE_FORMAT(st.starttime, '%Y-%m-%d %k:%i:%s') timeStart ,DATE_FORMAT(st.endtime,'%Y-%m-%d %k:%i:%s') timeEnd,DATE_FORMAT(sp.starttime, '%Y-%m-%d %k:%i:%s') stime ,DATE_FORMAT(sp.endtime,'%Y-%m-%d %k:%i:%s') etime, st.name,pl.initial,pl.product_title,stock.img,stock.price,stock.attribute, case when sp.starttime > now() then 1 when date_add(sp.endtime, interval 24 hour) < now() then 3 else 2 end as `status` from lkt_seconds_pro as sp LEFT JOIN lkt_seconds_time as st on sp.time_id = st.id and sp.store_id = st.store_id left join lkt_product_list as pl on pl.id = sp.pro_id and sp.store_id = pl.store_id left join lkt_configure stock on stock.id=sp.attr_id left join lkt_mch as m on m.id = pl.mch_id and sp.store_id = m.store_id
sp.num ${num_sort},
limit #{pageStart},#{pageEnd}

mapper.sql:
and a.goodsId = b.id
and b.recycle = 0
and b.mch_id=c.id
and b.brand_id=d.brand_id
and lab.id = a.label_id
and lab.recovery = 0
and pro.activity_id=a.id
and pro.is_delete=0
and substring_index(substring_index(b.product_class, '-', 2), '-', -1)=e.cid

    and a.is_delete=0
    and (a.is_delete=0 or a.is_delete=1)
    and a.is_delete=#{is_delete}


    and a.isshow=1
    
    and a.isshow=#{is_delete}

and a.store_id = #{store_id}
and b.status = #{goods_status}
and a.status = #{status}
and lab.mch_id = #{mchId}
and a.id = #{secGoodsId}
and a.label_id = #{labelId}
and a.delete_method != 1
AND(b.product_title like CONCAT('%', #{keyName},'%') or
    b.id =#{keyName})


    
        and #{sysDate}   <   a.starttime
        and #{sysDate}  >=  a.starttime and #{sysDate}   <=  
            a.endtime
        and #{sysDate}   >   a.endtime
    

and a.starttime   >=   #{startDate}
and a.endtime  <=   #{endDate}
and a.starttime   <=   #{heraldDate}
and pro.num > 0
and lab.is_show = 1

mapper.select:
SELECT COALESCE(SUM(b.num), 0) AS total_num
FROM lkt_seconds_record a
         INNER JOIN lkt_order b ON a.sno = b.sno
WHERE a.activity_id = #{activityId}
  AND a.user_id = #{userId}
  AND b.recycle = 0
  AND b.status != 7;
